// Build value tuples for each item
const values = items.map(item => {
  const url = item.json.url.replace(/'/g, "''"); // escape single quotes in URL
  const date = item.json.date;
  const title = item.json.title.replace(/'/g, ""); // escape single quotes in URL
  const origin = item.json.origin;
  const approved = 'FALSE';
  const industry_news = 'FALSE';
  const newsletter_id = '';

  return `('${url}', TO_DATE('${date}', 'MM/DD/YYYY'), '${title}' , '${origin}' , ${approved}, ${industry_news}, '${newsletter_id}', CURRENT_TIMESTAMP)`;
});

// Combine everything into a single safe SQL statement
const query = `
INSERT INTO curated_articles (url, publish_date, title, origin, approved, industry_news, newsletter_id, created_at)
VALUES
  ${values.join(',\n')}
ON CONFLICT (url)
DO UPDATE SET
  title = EXCLUDED.title,
  origin = EXCLUDED.origin,
  publish_date = EXCLUDED.publish_date,
  approved = EXCLUDED.approved,
  industry_news = EXCLUDED.industry_news,
  created_at = CURRENT_TIMESTAMP;
`;

return [
  {
    json: { 
      query: query.trim(),
    }
  }
];

const organic_links = [];

for (const item of $input.all()) {

  // Get source.
  const searchSource = item.json.search_parameters.engine;    

  // Check if organic_results exists and is an array
  if (item.json.organic_results && Array.isArray(item.json.organic_results)) {
    for (const linkObj of item.json.organic_results) {
      const date = new Date();
      if (linkObj.date !== undefined) {
        // Extract number and unit (supports: days, day, weeks, week)
        const regex = /(\d+)\s*(day|days|week|weeks)\s*ago/i;
        const match = linkObj.date.match(regex);

        if (match) {
          const value = parseInt(match[1], 10);
          const unit = match[2].toLowerCase();

          switch (unit) {
            case 'day':
            case 'days':
              date.setDate(date.getDate() - value);
            break;
            case 'week':
            case 'weeks':
              date.setDate(date.getDate() - value * 7);
            break;
          }
        }
      }
      organic_links.push({
        json: {
          url: linkObj.link,
          title: linkObj.title,
          origin: searchSource,
          date: date.toLocaleDateString('en-US'),
        },
      });
    }
  }
}

// Use a Map to filter unique URLs
const uniqueMap = new Map();

organic_links.forEach(item => {
  const url = item.json.url;
  if (!uniqueMap.has(url)) {
    uniqueMap.set(url, item); // keep the first occurrence
  }
});

// Convert back to array
return Array.from(uniqueMap.values());

